SPARQL {
DELETE { ?s ?p ?o . ?s1 ?p1 ?s . }
FROM <http://abc.io/test/ontology/properties>
WHERE {
  ?s ?p ?o . OPTIONAL { ?s1 ?p1 ?s . }
  ?s <http://www.w3.org/2000/01/rdf-schema#subPropertyOf> * <http://test1.com/test1> .
